import{_ as t,o as e,c as n,a2 as i}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Context as Infrastructure","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/principles/context-as-infrastructure.md","filePath":"ai-native/principles/context-as-infrastructure.md"}'),l={name:"ai-native/principles/context-as-infrastructure.md"};function s(o,a,r,c,p,h){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="context-as-infrastructure" tabindex="-1">Context as Infrastructure <a class="header-anchor" href="#context-as-infrastructure" aria-label="Permalink to &quot;Context as Infrastructure&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p>AI Native 组织需要把上下文当作基础设施和竞争力，而不是临时塞进 Prompt 的背景材料。</p><p>同样的模型，在模糊指令和高质量 Context 下会产生完全不同的结果。组织的长期优势不只来自采用了哪种 AI 工具，也来自它能否持续为人和 Agent 提供准确、相关、可追溯的 Context。</p><h2 id="原则" tabindex="-1">原则 <a class="header-anchor" href="#原则" aria-label="Permalink to &quot;原则&quot;">​</a></h2><ul><li>关键上下文必须可发现、可引用、可更新。</li><li>同一个事实只维护一个真源。</li><li>给人的文档和给 Agent 的指令应共享事实层，而不是各写一套。</li><li>上下文应靠近其拥有者：组织原则在 Handbook，项目契约在项目层，代码规则在仓库内。</li><li>临时对话不能成为长期决策的唯一载体。</li></ul><h2 id="好的上下文具备" tabindex="-1">好的上下文具备 <a class="header-anchor" href="#好的上下文具备" aria-label="Permalink to &quot;好的上下文具备&quot;">​</a></h2><ul><li>明确所有者</li><li>明确适用范围</li><li>可判断是否过期</li><li>能链接到证据或可执行资产</li><li>能被人和机器稳定定位</li></ul><h2 id="context-architecture-三层" tabindex="-1">Context Architecture 三层 <a class="header-anchor" href="#context-architecture-三层" aria-label="Permalink to &quot;Context Architecture 三层&quot;">​</a></h2><h3 id="context-org-chart" tabindex="-1">Context Org Chart <a class="header-anchor" href="#context-org-chart" aria-label="Permalink to &quot;Context Org Chart&quot;">​</a></h3><p>定义一个任务或项目需要哪些 Context，以及谁负责产生和维护。</p><p>它回答：</p><ul><li>关键 Context 散落在哪里？</li><li>哪些角色拥有这些信息？</li><li>谁负责更新，什么时候过期？</li><li>哪些内容默认暴露，哪些内容按需披露？</li></ul><p>这里的 Org Chart 不是传统汇报关系图，而是 Context 的生产、所有权和流动关系图。</p><h3 id="context-architecture" tabindex="-1">Context Architecture <a class="header-anchor" href="#context-architecture" aria-label="Permalink to &quot;Context Architecture&quot;">​</a></h3><p>设计 Context 从原始信息到可复用知识的流转方式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始证据</span></span>
<span class="line"><span>  -&gt; 结构化 Observation</span></span>
<span class="line"><span>  -&gt; 可检索项目知识</span></span>
<span class="line"><span>  -&gt; Agent 可消费的指令、Skill 和 Contract</span></span>
<span class="line"><span>  -&gt; 真实任务验证</span></span>
<span class="line"><span>  -&gt; 新证据</span></span></code></pre></div><p>它需要解决真源、版本、权限、检索、渐进式披露和知识晋升。</p><h3 id="context-toolchain" tabindex="-1">Context Toolchain <a class="header-anchor" href="#context-toolchain" aria-label="Permalink to &quot;Context Toolchain&quot;">​</a></h3><p>选择支撑 Context 流转的工具，例如：</p><ul><li>项目和组织文档</li><li>代码仓库与 <code>AGENTS.md</code></li><li>飞书知识库和协作 Thread</li><li>OpenClaw、Codex 和 Claude Code</li><li>MCP、CLI、搜索和结构化 Registry</li><li>Observation、Reflection 和评估工具</li></ul><p>工具链服务于 Context Architecture。不能因为某个工具方便，就让它成为未经设计的新真源。</p><h2 id="反模式" tabindex="-1">反模式 <a class="header-anchor" href="#反模式" aria-label="Permalink to &quot;反模式&quot;">​</a></h2><ul><li>同一规则复制到多个 <code>CLAUDE.md</code>、<code>AGENTS.md</code> 和 Wiki</li><li>用超长 Prompt 代替结构化文档</li><li>把聊天记录当作项目唯一历史</li><li>文档描述理想架构，但不链接真实实现</li><li>把全部历史无差别推入每次 Session</li><li>只建立规则库，却没有从真实工作持续产生新规则的机制</li></ul><h2 id="当前实践" tabindex="-1">当前实践 <a class="header-anchor" href="#当前实践" aria-label="Permalink to &quot;当前实践&quot;">​</a></h2><p>Evolution Handbook 使用组织、项目、仓库三级真源，并通过引用而非复制连接它们。</p><p>这仍是待验证的组织实践。完成至少一个项目的持续采用和复盘后，再评估是否升级为 <code>Adopted</code>。</p><h2 id="竞争力判断" tabindex="-1">竞争力判断 <a class="header-anchor" href="#竞争力判断" aria-label="Permalink to &quot;竞争力判断&quot;">​</a></h2><p>个人价值不会简单变成“谁提供的 Context 最多”。真正有价值的是：</p><ul><li>能识别任务所需的关键 Context</li><li>能判断来源可信度和时效</li><li>能把隐性知识转成可复用结构</li><li>能控制隐私、权限和无关信息</li><li>能让 Context 在执行后被验证和更新</li></ul><p>Context 越多不一定越好。相关、准确、及时和可操作比堆积信息更重要。</p><h2 id="闭环要求" tabindex="-1">闭环要求 <a class="header-anchor" href="#闭环要求" aria-label="Permalink to &quot;闭环要求&quot;">​</a></h2><p>上下文基础设施至少包含：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始证据</span></span>
<span class="line"><span>  → 观察</span></span>
<span class="line"><span>  → 反思与合并</span></span>
<span class="line"><span>  → 原则、契约、Skill 或 Playbook</span></span>
<span class="line"><span>  → 在真实任务中验证</span></span>
<span class="line"><span>  → 新证据</span></span></code></pre></div><p>只有存储，没有晋升和淘汰，不构成可持续记忆系统。</p>`,35)])])}const x=t(l,[["render",s]]);export{u as __pageData,x as default};
